#include <vector>
#include <algorithm>
#include <queue>
#include <unordered_map>
#include <climits>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Build the graph
    vector<vector<pair<long long, long long>>> graph(n);
    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        graph[u].push_back({v, w});
        graph[v].push_back({u, w});
    }

    // Use a priority queue to keep track of the maximum edge weights in each component
    priority_queue<long long> maxEdges;

    // Use a union-find (disjoint set union) structure to manage connected components
    vector<long long> parent(n), size(n);
    function<long long(long long)> find = [&](long long x) -> long long {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    };
    function<void(long long, long long)> unionSet = [&](long long x, long long y) -> void {
        long long rootX = find(x), rootY = find(y);
        if (rootX != rootY) {
            if (size[rootX] < size[rootY]) swap(rootX, rootY);
            parent[rootY] = rootX;
            size[rootX] += size[rootY];
        }
    };

    // Use a priority queue to process edges in order of increasing weight
    priority_queue<pair<long long, pair<long long, long long>>, vector<pair<long long, pair<long long, long long>>>, greater<>> pq;
    for (auto& edge : edges) {
        pq.push({edge[2], {edge[0], edge[1]}});
    }

    // Initialize DSU
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        size[i] = 1;
    }

    // Process edges in order of increasing weight
    while (!pq.empty()) {
        long long w = pq.top().first;
        long long u = pq.top().second.first;
        long long v = pq.top().second.second;
        pq.pop();

        long long rootU = find(u);
        long long rootV = find(v);

        if (rootU != rootV) {
            unionSet(rootU, rootV);
            maxEdges.push(w);
        }
    }

    // Now, we need to split the components into at most k components
    // The answer is the (total_components - k)th largest edge in maxEdges
